function focalPairPct(row,key){if(!row||typeof row!=="object")return{x:50,y:50};var k=key!=null?String(key).trim():"";var x=k&&row[k+"_focal_x"]!=null?Number(row[k+"_focal_x"]):row.image_focal_x!=null?Number(row.image_focal_x):Number(row.hero_focal_x);var y=k&&row[k+"_focal_y"]!=null?Number(row[k+"_focal_y"]):row.image_focal_y!=null?Number(row.image_focal_y):Number(row.hero_focal_y);if(!Number.isFinite(x))x=50;if(!Number.isFinite(y))y=50;return{x:Math.min(100,Math.max(0,x)),y:Math.min(100,Math.max(0,y)),};}
function objectPositionInline(row,key){var f=focalPairPct(row,key);return"object-position: "+f.x+"% "+f.y+"%";}
